insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chiyoda'), 'tokyo-chiyoda-air-conditioner-energy', '低所得世帯・生活保護受給世帯に対するエアコンの購入費助成（千代田区）', '千代田区が、住民税非課税世帯・均等割のみ課税世帯・児童扶養手当受給世帯・生活保護受給世帯などのうち、冷房が使用できるエアコンを一台も保有していない、または製造から10年が経過したエアコンのみを使用している世帯を対象に、エアコン本体の購入費および設置費（既存エアコンの撤去費を含む）の一部を助成する区独自の制度です。熱中症予防を目的としています。助成額は1世帯あたり最大10万円（1台分）が上限とされています。対象や上限額、受付状況は年度により変わるため、必ず千代田区の公式情報でご確認ください。', '千代田区では、住民税非課税世帯や生活保護を受けている世帯などで、エアコンを持っていない、または古いエアコン（製造から10年以上）しか使っていない世帯に対して、エアコンを買って取り付ける費用を助成しています。熱中症から身を守るための制度で、1世帯あたり最大10万円が上限です。対象になるかどうかや申請のしかたは、千代田区の専用コールセンターや公式ホームページで確認してください。', 'subsidy', '千代田区内の世帯のうち、令和7年度または令和8年度の住民税非課税世帯・住民税均等割のみ課税世帯、申請日現在の児童扶養手当受給世帯、生活保護受給世帯などで、冷房が使用できるエアコンを一台も保有していない、または製造から10年が経過したエアコンのみを使用している世帯が対象とされています。具体的な対象要件は公式でご確認ください。', '1世帯あたり最大10万円（エアコン1台分）が上限とされています。エアコン本体の購入費および設置費（現在使用しているエアコンの撤去費を含む）が対象で、電池等の消耗品や延長保証は対象外とされています。金額・対象範囲は年度により変わる場合があるため公式でご確認ください。', '令和8年度は、申請相談受付が令和8年5月1日～10月16日午後5時、交付申請書受付が令和8年5月1日～10月末日、請求書提出期限が11月16日とされています。受付期間は単年度ごとに設定されるため、最新の期間は公式でご確認ください。', 'まず専用コールセンター等に申請相談し、自宅訪問による状況確認を受けたうえで申請書を提出し、交付決定後にエアコンを購入、請求書を提出して助成金の交付を受ける流れとされています。詳細な手順・必要書類は公式でご確認ください。', '申請書（訪問確認時に交付）、エアコン購入・設置費用の領収書、課税（非課税）証明書（千代田区への転入の場合）などが必要とされています。詳細は公式でご確認ください。', FALSE, '千代田区 生活支援課（低所得世帯向け専用コールセンター／生活保護受給世帯は相談・保護係）', '03-5211-4231', 'https://www.city.chiyoda.lg.jp/koho/kenko/sekatsu/airconditioner-josei.html', 'https://www.city.chiyoda.lg.jp/koho/kenko/sekatsu/airconditioner-josei.html', '低所得世帯・生活保護受給世帯に対するエアコンの購入費助成｜千代田区', '2026-06-27', 'high', ARRAY['requiredDocumentsText']::text[], '本情報は千代田区公式サイトの掲載内容（2026-06-27確認）に基づく概要です。対象要件・上限額・申請期間・受付状況は年度により変更される場合があるため、申請前に必ず千代田区の公式情報および担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
