insert into public.support_program_life_events (support_program_id, life_event_id) select sp.id, le.id from public.support_programs sp, public.life_events le where sp.slug = 'tokyo-chiyoda-air-conditioner-energy' and le.slug = 'hardship' on conflict do nothing;
