insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-chiyoda-air-conditioner-energy","status":"published","title":"低所得世帯・生活保護受給世帯に対するエアコンの購入費助成（千代田区）","officialUrl":"https://www.city.chiyoda.lg.jp/koho/kenko/sekatsu/airconditioner-josei.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-chiyoda-air-conditioner-energy:dG9reW8tY2hpeW9kYS1haXItY29uZGl0aW9uZXIt' from public.support_programs sp where sp.slug='tokyo-chiyoda-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chuo'), 'tokyo-chuo-air-conditioner-energy', '住民税非課税世帯等エアコン購入費助成（中央区）', '中央区が、経済的理由で自宅用エアコンの購入が困難な世帯を対象に、夏季の熱中症による健康被害を予防する目的でエアコン本体の購入費と設置工事費を助成する区独自の制度です。自宅に使用できるエアコンが1台もない世帯（故障で冷房機能が使用できないエアコンしかない世帯を含む）のうち、世帯全員が住民税非課税、生活保護受給中、または中国残留邦人等支援給付受給中の世帯が対象となる可能性があります。助成上限はエアコン本体購入費と設置工事費あわせて10万円（税込）です。助成決定通知を受ける前に購入したエアコンは対象外となるため、購入前の申請が必要です。対象条件・上限額・申請受付期間・最新の受付状況は中央区公式サイトでご確認ください。', '中央区では、エアコンがなくて夏の暑さが心配な世帯のうち、住民税が非課税の世帯や生活保護を受けている世帯などを対象に、エアコンの購入と取り付けの費用を最大10万円まで助成する制度があります。必ず買う前に区へ申請することが必要です。申請の締切や受付状況は中央区の公式サイトや問い合わせ先で確認してください。', 'subsidy', '申込時点で中央区に住民登録があり中央区に居住し、自宅に使用できるエアコンが1台もない世帯（故障で冷房機能が使用できないエアコンしかない世帯を含む）で、世帯全員が住民税非課税、または生活保護受給中、もしくは中国残留邦人等支援給付受給中の世帯が対象となる可能性があります。住民税均等割が課税されている方と同居している場合は対象外となる可能性があります。詳しい対象条件は公式でご確認ください。', '助成上限額：エアコン本体購入費と設置工事費あわせて100,000円（税込）。上限を超える費用は自己負担となる可能性があります。最新の金額は公式で確認してください。', '公式ページに具体的な申請受付期間・締切の明記は確認できませんでした。受付期間・締切は中央区へお問い合わせのうえ公式でご確認ください。', '電子申請（LoGoフォーム）または郵送による申請が可能とされています。助成決定通知を受けてから購入したエアコンが対象で、申請後に区の委託担当者が自宅を訪問し設置状況を確認するとされています。具体的な手続きは公式でご確認ください。', '助成金請求書や領収書等の提出が必要とされています。生活保護世帯等はエアコン本体代金と設置工事費用の内訳が記載された領収書が求められる場合があります。必要書類の詳細は公式・交付決定通知でご確認ください。', TRUE, '中央区福祉保健部地域福祉課エアコン購入費助成担当', '03-3546-5630', 'https://www.city.chuo.lg.jp/a0019/kenkouiryou/fukushiippan/seikatsushien/airconjosei.html', 'https://www.city.chuo.lg.jp/a0019/kenkouiryou/fukushiippan/seikatsushien/airconjosei.html', '住民税非課税世帯等エアコン購入費助成 - 中央区', '2026-06-27', 'high', ARRAY['applicationDeadlineText', '申請受付期間', '受付状況', 'benefitAmountText', 'requiredDocumentsText']::text[], '本情報は中央区公式サイトをもとにまとめた概要です。対象条件・助成額・申請受付期間・受付状況は変更される場合があります。申請の可否や受給は区の審査によります。必ず公式サイト・問い合わせ先で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
