insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-chuo-air-conditioner-energy","status":"published","title":"住民税非課税世帯等エアコン購入費助成（中央区）","officialUrl":"https://www.city.chuo.lg.jp/a0019/kenkouiryou/fukushiippan/seikatsushien/airconjosei.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-chuo-air-conditioner-energy:dG9reW8tY2h1by1haXItY29uZGl0aW9uZXItZW5l' from public.support_programs sp where sp.slug='tokyo-chuo-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'minato'), 'tokyo-minato-air-conditioner-energy', '高齢者エアコン購入設置費助成（港区）', '港区が、自宅にエアコンがない又は故障で使えない住民税非課税の高齢者世帯等に対し、夏季の熱中症対策としてエアコンの購入・設置費用を助成する制度です。令和8年度（2026年度）の助成上限は1世帯1回限り111,000円で、購入・設置にかかった費用と上限額のいずれか少ない額が助成される可能性があります。対象や上限額、申請期間は変わり得るため、必ず港区の公式ページや高齢者相談センターで最新情報をご確認ください。', 'エアコンがなくて夏の暑さがつらい、住民税が非課税の高齢者世帯などに、港区がエアコンの購入と取り付けの費用を助けてくれる制度です。令和8年度は1世帯につき1回まで、最大で11万1千円までが助成される可能性があります。まずはお住まいの地区の高齢者相談センターに相談してみてください。条件や金額・受付の時期は変わることがあるので、必ず港区の公式ページで最新の内容を確かめてください。', 'subsidy', '港区内に居住し、自宅にエアコンがない又は故障により使用できない世帯で、(1)65歳以上のひとり暮らし世帯、65歳以上の高齢者のみで構成される世帯、又は65歳以上の高齢者と障害者のみで構成される世帯であり、(2)世帯員全員が住民税非課税である世帯が対象となる可能性があります。詳細な要件は公式ページでご確認ください。', '令和8年度（2026年度）の助成上限は1世帯1回限り111,000円。エアコンの購入・設置等にかかった費用と上限額のいずれか少ない額を助成（保証延長費は対象外）と公式に記載されています。年度により上限額が変わる可能性があるため公式で要確認。', '今年度の受付期間・申請期限は公式ページに明示がありません。先着・予算枠で締め切られる場合があるため、早めに高齢者相談センターへお問い合わせください。', '各地区の高齢者相談センターで相談・申請受付を行うと公式ページに記載されています。申請の流れや必要書類、今年度の受付期間は変更される場合があるため、事前に高齢者支援課在宅支援係または高齢者相談センターへお問い合わせのうえ公式ページでご確認ください。', '必要書類は公式ページに具体的な記載がなく、年度により異なる可能性があります。高齢者相談センターまたは高齢者支援課在宅支援係にお問い合わせのうえ公式案内でご確認ください。', FALSE, '港区 保健福祉支援部 高齢者支援課 在宅支援係（各地区の高齢者相談センター）', '03-3578-2406', NULL, 'https://www.city.minato.tokyo.jp/zaitakushien/eakonn.html', '港区ホームページ／高齢者エアコン購入設置費用助成', '2026-06-27', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText', 'benefitAmountText', 'onlineApplicationAvailable']::text[], '本情報は港区公式ページ（2026-06-27確認）に基づく概要です。対象・上限額・申請期間・必要書類は変更される場合があるため、申請前に必ず港区公式ページおよび高齢者相談センターで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
