insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-minato-air-conditioner-energy","status":"published","title":"高齢者エアコン購入設置費助成（港区）","officialUrl":"https://www.city.minato.tokyo.jp/zaitakushien/eakonn.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-minato-air-conditioner-energy:dG9reW8tbWluYXRvLWFpci1jb25kaXRpb25lci1l' from public.support_programs sp where sp.slug='tokyo-minato-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinjuku'), 'tokyo-shinjuku-air-conditioner-energy', '新宿区 低所得世帯・生活保護受給世帯に対するエアコン購入費助成', '新宿区が、住民税非課税世帯や生活保護受給世帯など熱中症リスクの高い低所得・要援護世帯のうち、申請時点でエアコンを持たない世帯を対象に、エアコン本体の購入・設置費用の一部（1世帯につき10万円まで）を助成する区独自の制度です。対象・上限額・受付期間は公式で必ずご確認ください。', 'エアコンがなくて夏の暑さがつらい、収入の少ないご家庭などのために、新宿区がエアコンを買って取り付ける費用の一部（1世帯10万円まで）を助ける制度です。まず電話（0120-612-303）で申し込みます。対象になるかどうかや締め切りは、区の公式ページで確かめてください。', 'subsidy', '令和7・8年度住民税非課税世帯、住民税均等割のみ課税世帯、児童扶養手当受給世帯、生活保護受給世帯、または乳幼児・障害者がいる等の特別な事情でエアコンの追加設置が必要な世帯で、申請時点で冷房機能付きエアコンを保有していない区民が対象です。具体的な対象要件は新宿区の公式ページでご確認ください。', '1世帯につきエアコン本体の購入・設置等にかかる費用として10万円までが助成されます。年度・予算により変わる可能性があるため公式でご確認ください。', '申請受付終了（予定）は令和8年（2026年）9月30日とされています。受付状況・期間は年度や予算により変動するため公式でご確認ください。', 'まずコールセンター（0120-612-303、平日8:30～17:00）へ電話で申し込み、その後スタッフによる自宅訪問確認を受け、審査を経て交付決定通知書が郵送されます。届いた通知書を協力店舗に提示してエアコンを注文する流れとされています。詳細・最新の手順は公式ページや問い合わせ先でご確認ください。', '訪問確認時に対象世帯であることの確認が行われるとされていますが、必要書類の詳細は公式ページに一覧の記載がないため、問い合わせ先でご確認ください。', FALSE, '新宿区 福祉部 地域福祉課 福祉計画係', '0120-612-303', 'https://www.city.shinjuku.lg.jp/fukushi/fukushi01_000001_00037.html', 'https://www.city.shinjuku.lg.jp/fukushi/fukushi01_000001_00037.html', '新宿区低所得世帯・生活保護受給世帯に対するエアコン購入費助成', '2026-06-27', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText']::text[], '対象要件・助成上限額・申請受付期間・受付状況は年度や予算により変わる可能性があります。最新かつ正確な情報は必ず新宿区の公式ページおよび問い合わせ先でご確認ください。本情報は受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
