insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-shinjuku-air-conditioner-energy","status":"published","title":"新宿区 低所得世帯・生活保護受給世帯に対するエアコン購入費助成","officialUrl":"https://www.city.shinjuku.lg.jp/fukushi/fukushi01_000001_00037.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-shinjuku-air-conditioner-energy:dG9reW8tc2hpbmp1a3UtYWlyLWNvbmRpdGlvbmVy' from public.support_programs sp where sp.slug='tokyo-shinjuku-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'bunkyo'), 'tokyo-bunkyo-air-conditioner-energy', '文京区 生活困窮者エアコン設置緊急支援事業', '文京区が、経済的な理由でエアコンの設置が難しい生活困窮世帯を対象に、エアコン本体・設置工事費などの購入・設置費用を助成する区独自の制度です。住民税非課税世帯や均等割のみ課税世帯、児童扶養手当受給世帯などが対象となる可能性があり、1世帯あたり上限10万円(1世帯1台)が助成されます。詳細・最新の対象や受付状況は文京区公式ページで確認してください。', 'エアコンがなくて夏に困っている、収入が少ない世帯のために、文京区がエアコン本体や取り付けの費用を最大10万円まで助けてくれる制度です。住民税がかからない世帯などが対象になることがあります。対象になるかどうかや申し込み方法は、区の窓口やコールセンターに確認してください。', 'subsidy', '文京区内に居住し住民登録のある世帯のうち、住民税非課税世帯・住民税均等割のみ課税世帯・児童扶養手当受給世帯などで、エアコンが未設置・故障で使用不可・製造から15年以上経過しているなどの条件に該当する世帯が対象となる可能性があります(生活保護受給世帯を除く)。賃貸の場合は家主の承諾が必要です。詳しい対象要件は公式で確認してください。', '1世帯あたり上限10万円(1世帯1台限り)。対象経費はエアコン本体代金、配送費、設置工事費、撤去費、リサイクル費など(延長保証料・修理費は対象外)。金額・対象経費は公式で確認してください。', '令和8年(2026年)5月25日～10月31日(郵送は当日消印有効)。確認日(2026-06-27)時点で受付中ですが、受付期間は年度により変わる可能性があるため公式で確認してください。', '電子申請、またはコールセンター(0120-860-563、月～金 9時～17時)に連絡して郵送で申請します。申請方法・必要書類はコールセンターまたは公式ページで確認してください。', '必要書類は公式ページまたはコールセンターで確認してください(申請時に案内されます)。', TRUE, '文京区 福祉部生活福祉課 自立支援担当 / エアコン設置緊急支援コールセンター', '03-5803-1917 / 0120-860-563', 'https://www.city.bunkyo.lg.jp/b019/p006559.html', 'https://www.city.bunkyo.lg.jp/b019/p006559.html', 'エアコン設置緊急支援 | 文京区', '2026-06-27', 'high', ARRAY['applicationDeadlineText', 'benefitAmountText', 'targetPeople', 'requiredDocumentsText']::text[], '本情報は文京区公式ページ(2026-06-27確認)に基づく概要です。対象要件・助成額・受付期間・必要書類は変更される場合があります。申請にあたっては必ず文京区公式ページおよびコールセンターで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
