insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-bunkyo-air-conditioner-energy","status":"published","title":"文京区 生活困窮者エアコン設置緊急支援事業","officialUrl":"https://www.city.bunkyo.lg.jp/b019/p006559.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-bunkyo-air-conditioner-energy:dG9reW8tYnVua3lvLWFpci1jb25kaXRpb25lci1l' from public.support_programs sp where sp.slug='tokyo-bunkyo-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'taito'), 'tokyo-taito-air-conditioner-energy', '低所得世帯（非課税）および生活保護世帯エアコン購入費助成事業', '台東区が、住民税非課税世帯および生活保護世帯を対象に、熱中症予防のためのエアコン購入・設置にかかる費用を助成する制度です。自宅にエアコンがない、または故障で冷房が使えない世帯が対象で、購入費・配送費・設置費・リサイクル費・撤去費が助成対象とされています。助成は一世帯一回限りで、上限額があります。詳細・最新の要件は公式ページで確認してください。', 'エアコンがない、またはこわれて冷房が使えない家庭のうち、住民税がかからない世帯や生活保護を受けている世帯が対象です。台東区がエアコンの購入や取り付けの費用を、上限のある範囲で一世帯につき一回助成します。まずはコールセンターに相談してから申し込む流れです。生活保護を受けている方は担当のケースワーカーに相談します。', 'subsidy', '台東区に住所があり、令和7年度または令和8年度の住民税が世帯全員非課税で、自宅にエアコンがない（または故障で全てのエアコンの冷房機能が使えない）世帯。生活保護世帯も対象だが、申請は担当ケースワーカーへの相談が窓口となる。詳しい要件は公式で確認。', '助成対象費用と上限額のいずれか低い額を、一世帯につき一回助成（公式ページ上の上限は10万円）。対象費用にはエアコン購入費・配送費・設置費・リサイクル費・撤去費が含まれるとされる。金額・対象範囲は年度により変わりうるため公式で確認。', '申請締切は公式ページ上で令和8年（2026年）10月30日（金曜日）、領収書等の提出期限は令和8年12月28日とされる。単年度事業のため期間は変わりうるので公式で確認。', '原則として、まず台東区低所得世帯エアコン購入費用助成コールセンター（0120-031-890）で事前相談し、訪問・申請、承認通知を受けたうえでエアコンを購入・設置し、領収書等を提出する流れ。生活保護世帯は担当ケースワーカーに相談する。手順の詳細は公式ページで確認。', '購入先が発行する領収書および、本体・設置・配送・リサイクル等の費用内訳がわかる書類等。詳細は公式ページおよびコールセンターで確認。', FALSE, '台東区低所得世帯エアコン購入費用助成コールセンター（生活保護世帯は保護課）', '0120-031-890（生活保護世帯は保護課 03-5246-1181）', 'https://www.city.taito.lg.jp/kenkohukusi/seikatsuokomari/seikatsuhogo/teisyotoku_eakon.html', 'https://www.city.taito.lg.jp/kenkohukusi/seikatsuokomari/seikatsuhogo/teisyotoku_eakon.html', '低所得世帯（非課税）および生活保護世帯エアコン購入費助成事業 - 台東区', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は確認日（2026-06-27）時点の台東区公式ページに基づく概要です。対象要件・上限額・申請期間・必要書類は変更される場合があるため、申請前に必ず公式ページおよびコールセンターで最新情報を確認してください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
