insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'sumida'), 'tokyo-sumida-air-conditioner-energy', '墨田区住民税非課税世帯等エアコン購入費助成事業', '熱中症対策として、エアコンが1台もない、または故障で1台も動くエアコンがない住民税非課税世帯・生活保護受給世帯に対し、墨田区がエアコンの購入費と設置工事費の一部を助成する制度です。購入費と設置工事費をあわせて最大111,000円（税込）まで助成される可能性があります（上限額の内訳は購入費73,000円・設置工事費38,000円）。申請は「すみだエアコン助成コールセンター」への電話申込みで行います。対象要件・上限額・受付期間は年度により変わる可能性があるため、必ず墨田区公式ページで最新情報をご確認ください。', '夏の暑さ対策として、お金の負担が大きい非課税世帯や生活保護世帯で、家にエアコンが1台もない（または壊れて動かない）方に、墨田区がエアコンを買って取り付ける費用の一部（最大で11万1千円ほど）を助ける制度です。電話で申し込みます。対象や金額・受付期間は年度によって変わることがあるので、必ず区の公式ページで確認してください。', 'subsidy', '墨田区に住民登録があり、住民税が世帯全員非課税の世帯（令和7年度又は令和8年度）または墨田区で生活保護を受給している世帯で、かつ居住する住居にエアコンが1台もない、もしくは故障で1台も動くエアコンがない世帯が対象となる可能性があります。なお令和6年度の同事業を利用した世帯は対象外とされています。具体的な対象要件は墨田区公式で確認してください。', '最大111,000円（税込）まで助成される可能性があります。内訳の上限はエアコン購入費73,000円（税込）、設置工事費38,000円（税込）です（公式で確認）。', '令和8年度は受付期間が令和8年3月23日から8月31日まで、申込期限が令和8年7月31日とされています。受付期間・期限は年度により変わる可能性があるため、公式で最新情報をご確認ください。', '「すみだエアコン助成コールセンター」（電話：03-6821-6979）への電話で申し込みます。「墨田区エアコン購入費助成金請求書兼口座振替依頼書」や購入費・設置工事費が分かる領収書などの書類が必要となる可能性があります。詳細は公式ページや同コールセンターでご確認ください。', '購入費・設置工事費それぞれの金額が分かる領収書、および「墨田区エアコン購入費助成金請求書兼口座振替依頼書」などが必要となる可能性があります。詳しくは公式ページ・コールセンターでご確認ください。', FALSE, 'すみだエアコン助成コールセンター', '03-6821-6979', NULL, 'https://www.city.sumida.lg.jp/kenko_fukushi/seikatuhukusi/eakon.html', '墨田区住民税非課税世帯等エアコン購入費助成事業について（墨田区公式ホームページ）', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は墨田区公式ページをもとにした概要です。対象要件・助成額・受付期間・必要書類は変更される場合があります。申請の可否や具体的な手続きは、必ず墨田区公式ページおよびコールセンターでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
