insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-sumida-air-conditioner-energy","status":"published","title":"墨田区住民税非課税世帯等エアコン購入費助成事業","officialUrl":"https://www.city.sumida.lg.jp/kenko_fukushi/seikatuhukusi/eakon.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-sumida-air-conditioner-energy:dG9reW8tc3VtaWRhLWFpci1jb25kaXRpb25lci1l' from public.support_programs sp where sp.slug='tokyo-sumida-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'koto'), 'tokyo-koto-air-conditioner-energy', '高齢者エアコン購入費助成（江東区）', '江東区が、経済的な事情でエアコンの購入が困難な高齢者のみ世帯のうち住民税非課税世帯などを対象に、熱中症予防のためエアコン本体の購入・設置にかかる費用を助成する区独自の制度です。対象となる可能性のある世帯は、エアコン本体購入費・配送費・設置工事費・撤去費（リサイクル料金含む）について上限10万円（1世帯1台1回限り）の助成を受けられる可能性があります。対象条件・上限額・申請期間・受付状況は年度により変わる場合があるため、必ず江東区公式で最新情報をご確認ください。', '江東区では、65歳以上だけで暮らしていて住民税がかからない世帯などで、家に使えるエアコンがない場合に、エアコンを買って取り付ける費用を最大10万円まで助けてもらえる場合があります。熱中症から身を守るための制度です。申し込みには電話での予約や自宅の訪問調査があり、受付の期間が毎年決まっています。対象になるかや条件は年度で変わることがあるので、江東区の公式ページで最新の内容を確認してください。', 'subsidy', '江東区に住民票があり、基準日時点で65歳以上の一人暮らしまたは高齢者のみで構成される世帯のうち、住民税非課税世帯（生活保護受給世帯を含む）で、自宅に使用できるエアコンがない世帯が対象となる可能性があります。具体的な対象要件・基準日は年度により異なるため、公式で確認してください。', 'エアコン本体購入費・配送費・設置工事費・撤去費（リサイクル料金含む）について上限10万円（1世帯1台1回限り）。延長保証料や室外機カバー等は対象外とされています（年度により変動の可能性、公式で確認）。', '令和8年度の例では、訪問調査予約は6月30日まで、訪問調査・申請書提出は7月31日まで、購入・設置は8月31日まで、助成金請求は9月18日まで。単年度ごとの受付で締切が設定されているため、最新の期間は公式で確認が必要です。', '江東区エアコン購入費助成金コールセンター等への連絡により訪問調査を予約し、自宅訪問調査を受けたうえで申請書を提出します。交付決定後にエアコンを購入・設置し、領収書等を添えて助成金を請求する流れです。申請期間や各手続きの締切は年度により異なるため、必ず公式の最新案内で確認してください。', '申請書、エアコン購入の領収書（コピー）、振込先口座を記入した請求書など。詳細・最新の必要書類は公式で確認してください。', FALSE, '江東区 福祉部 長寿応援課 長寿応援係', '03-3647-4541', NULL, 'https://www.city.koto.lg.jp/211100/koureisyaeakonjyosei.html', '高齢者エアコン購入費助成 - 江東区', '2026-06-27', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は江東区公式ページをもとにした概要です。対象条件・助成上限額・申請期間・受付状況は年度により変動する場合があります。申請にあたっては必ず江東区の公式案内および窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
