insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-koto-air-conditioner-energy","status":"published","title":"高齢者エアコン購入費助成（江東区）","officialUrl":"https://www.city.koto.lg.jp/211100/koureisyaeakonjyosei.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-koto-air-conditioner-energy:dG9reW8ta290by1haXItY29uZGl0aW9uZXItZW5l' from public.support_programs sp where sp.slug='tokyo-koto-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinagawa'), 'tokyo-shinagawa-air-conditioner-energy', '品川区住民税非課税世帯エアコン購入費等助成事業', '経済的な理由によりエアコンを設置することが難しい住民税非課税世帯に対し、エアコン本体の購入費や配送費・設置工事費・撤去費を上限10万円まで助成する品川区独自の制度です。自宅に使用可能なエアコンが1台もない世帯が対象となる可能性があります。熱中症予防の観点から、低所得世帯の冷房環境整備を支援するものです。詳細・最新の対象や受付状況は品川区の公式ページでご確認ください。', 'エアコンがなく、住民税が非課税の品川区の世帯に、エアコンを買って取り付けるお金を最大10万円まで区が出してくれる制度です。必ずエアコンを買う前に申し込みが必要です。まず電話かインターネットで訪問調査を申し込みます。受付は毎年5月から7月ごろです。くわしくは品川区にお問い合わせください。', 'subsidy', '申請日時点で品川区内に住民登録があり、令和7年度分または令和8年度分の住民税が非課税である世帯（生活保護受給世帯を含む）で、自宅に使用可能なエアコンが1台もない世帯が対象となる可能性があります。生活保護受給世帯は冷房器具の支給要件に該当しない場合が条件です。具体的な対象要件は公式で確認してください。', '上限100,000円（エアコン本体購入費・配送費・設置工事費・撤去費の合計）。金額・対象経費は公式で確認してください。', '申請期間は令和8年5月1日〜7月31日（確認日2026-06-27時点で受付中）。年度ごとに期間が変わる可能性があるため公式で確認してください。', '電子申請または電話で訪問調査を申し込む方式です。助成金の交付決定前に購入したエアコンは助成対象外となるため、必ず購入前に訪問調査の申請を行う必要があります。手続きの詳細は公式ページで確認してください。', '公式ページに必要書類の明記はありません。訪問調査の申し込み後に案内される可能性があるため、詳細は品川区生活福祉課にご確認ください。', TRUE, '品川区 生活福祉課 エアコン助成担当', '03-5742-3848', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-seikatsukomaru/20230428084925.html', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-seikatsukomaru/20230428084925.html', '品川区住民税非課税世帯エアコン購入費等助成事業｜品川区', '2026-06-27', 'high', ARRAY['requiredDocumentsText', 'benefitAmountText', 'applicationDeadlineText', 'targetPeople']::text[], '対象要件・助成額・受付期間は変更される場合があります。最新かつ正確な情報は必ず品川区の公式ページや担当課でご確認ください。本サイトは申請の代行や受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
