insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-shinagawa-air-conditioner-energy","status":"published","title":"品川区住民税非課税世帯エアコン購入費等助成事業","officialUrl":"https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-seikatsukomaru/20230428084925.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-shinagawa-air-conditioner-energy:dG9reW8tc2hpbmFnYXdhLWFpci1jb25kaXRpb25l' from public.support_programs sp where sp.slug='tokyo-shinagawa-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'meguro'), 'tokyo-meguro-air-conditioner-energy', '非課税等高齢者世帯のエアコン購入費助成（目黒区）', '目黒区が、室内での熱中症予防対策として、住民税非課税の高齢者のみの世帯（または高齢者と障害者のみの世帯）で、自宅にエアコンがない、または故障で冷房が使えない世帯に対し、エアコン本体購入費・設置費等の一部を助成する区独自の制度です。助成上限は10万円とされています（公式で確認・要審査）。申請には地域包括支援センター職員による訪問調査が必要で、受付期間が定められています。対象・上限額・期限は公式サイトで最新情報をご確認ください。', '目黒区では、住民税が非課税の高齢者だけの世帯（または高齢者と障害のある方だけの世帯）で、家にエアコンがない、または壊れて冷房が使えない場合に、エアコンを買って取り付ける費用を最大10万円まで助成しています。まず福祉総合課くらしの相談係（03-5722-6840）に連絡すると、地域包括支援センターの職員が家を訪ねて確認し、その場で申し込み手続きをします。申し込みには期限があるので、公式サイトで最新の内容を確かめてください。', 'subsidy', '目黒区に住民登録があり、満65歳以上の高齢者のみ、または満65歳以上の高齢者と障害者（身体障害者手帳・愛の手帳・精神障害者保健福祉手帳のいずれかをお持ちの方）のみで構成される世帯で、世帯全員が住民税非課税または生活保護受給中であり、自宅にエアコンがない（または故障等で冷房機能が使用できない）方が対象となる可能性があります。詳細な要件は目黒区公式サイトでご確認ください。', '助成上限10万円（公式で確認）。対象経費はエアコン本体購入費、配送費、設置工事費、撤去費（リサイクル料金含む）とされています。修理費・延長保証料・申請者自身による設置工事費は対象外とされています。上限額・対象経費は年度により変動しうるため公式サイトでご確認ください。', '訪問調査予約・申請書提出の期限は令和8年（2026年）9月30日、助成金請求の期限は令和8年（2026年）11月30日とされています（単年度・公式で確認）。', '事前予約のうえ、地域包括支援センター職員（生活保護受給世帯は担当ケースワーカー）による自宅訪問調査を受け、その場で申請書を提出します。交付決定通知後にエアコンを購入・設置し、助成金を請求する流れとされています。まず目黒区福祉総合課くらしの相談係（電話03-5722-6840）へお問い合わせのうえ、公式サイトで手順をご確認ください。', '請求書（振込先口座記入）、振込先通帳の写し、領収書の写し、設置確認書類などが必要とされています。詳細は公式サイトでご確認ください。', FALSE, '目黒区 福祉総合課 くらしの相談係', '03-5722-6840', 'https://www.city.meguro.tokyo.jp/fukushisougou/kenkoufukushi/seikatsushien/airconditioner.html', 'https://www.city.meguro.tokyo.jp/fukushisougou/kenkoufukushi/seikatsushien/airconditioner.html', '非課税等高齢者世帯のエアコン購入費を助成します | 目黒区', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは目黒区公式サイトの情報をもとにした概要です。対象要件・上限額・受付期間は変更される場合があります。申請の可否や金額は審査により決まります。最新かつ正確な情報は必ず目黒区公式サイトおよび担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
