insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'ota'), 'tokyo-ota-air-conditioner-energy', '大田区エアコン設置緊急支援事業', '自宅に使用できるエアコンがない区民のうち、住民税非課税世帯・均等割のみ課税世帯・児童扶養手当受給世帯のいずれかに該当する世帯に対し、熱中症予防のためエアコンの購入・設置費用を助成する大田区独自の制度です。助成上限は1世帯あたり10万円（1台）で、本体購入費・配送費・設置工事費・撤去/リサイクル費・事前現地確認費が対象経費となる可能性があります。詳細・最新の対象要件は公式で確認してください。', 'エアコンがなくて困っている大田区の低所得世帯などに、エアコンを買って取り付ける費用を区が助けてくれる制度です。上限は10万円。まずコールセンターに電話して相談します。', 'subsidy', '自宅に使用できるエアコンが1台も設置されておらず大田区に住民票がある方で、住民税非課税世帯・住民税均等割のみ課税世帯・児童扶養手当受給世帯のいずれかに該当する世帯が対象となる可能性があります。具体的な対象要件は公式で確認してください。', '助成上限は1世帯あたり10万円（1台）とされています（公式で確認してください）。', '受付期間は令和8年6月1日～令和9年2月28日とされています（確認日時点で受付継続中。最新の受付状況は公式で確認してください）。', '専用コールセンター（03-3731-7390）に電話相談のうえ、お住まいの地域を管轄する地域福祉課へ申請します。訪問調査・交付決定を経て購入・設置し、交付金を請求する流れとされています。詳細は公式で確認してください。', '申請書はダウンロードできますが、添付書類の詳細は各地域福祉課への確認が案内されています。公式で確認してください。', FALSE, '大田区エアコン設置緊急支援事業専用コールセンター', '03-3731-7390', NULL, 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/shien/eaconjosei.html', '大田区ホームページ：大田区エアコン設置緊急支援事業', '2026-06-27', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '対象要件・助成額・受付期間は変更される場合があります。申請の可否や受給は審査によります。必ず大田区の公式情報・コールセンターでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
