insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'setagaya'), 'tokyo-setagaya-air-conditioner-energy', '低所得世帯エアコン購入費等助成（世田谷区）', '世田谷区が、夏季の熱中症による健康被害を予防するため、自宅に使用可能なエアコンが1台もない低所得世帯（住民税非課税等・生活保護非受給）を対象に、エアコンの購入・設置費用の一部または全部を助成する区独自の制度です。助成は1世帯1台1回限りで、上限は10万円と実際の購入設置費用のいずれか低い額とされています（公式で確認してください）。', '夏の暑さで体調をくずさないように、世田谷区が家にエアコンがない低所得の世帯へ、エアコンを買って取り付ける費用を助けてくれる制度です。住民税がかかっていない世帯などが対象になる可能性があります。くわしい条件や金額は区の公式ページで確認してください。', 'subsidy', '世田谷区民で、自宅に使用可能なエアコンが1台もなく、世帯全員が住民税非課税または均等割のみ課税で、生活保護を受給していない世帯が対象となる可能性があります。詳細な要件は公式でご確認ください。', '1世帯1台1回限り。上限10万円と実際の購入・設置費用のいずれか低い額（公式で確認してください。年度により変動する可能性があります）。', '令和8年（2026年）4月15日～10月30日（郵送は当日消印有効）。確認日時点では受付期間内ですが、最新の受付状況は公式で確認してください。', 'オンライン申請（LOGOフォーム）または郵送による申請。申請期間は令和8年（2026年）4月15日～10月30日（郵送は当日消印有効）とされています。申請前の問い合わせはせたがやコール（03-5432-3333）、申請後は生活福祉課（03-5432-2188）が窓口とされています。受付状況・期間は年度により変わる可能性があるため公式で確認してください。', '本人確認書類、税証明書類（該当者）、交付申請書、提出書類確認表など（公式で確認してください）。', TRUE, '世田谷区 保健福祉政策部 生活福祉課', '03-5432-2188', 'https://www.city.setagaya.lg.jp/02412/31918.html', 'https://www.city.setagaya.lg.jp/02412/31918.html', '低所得世帯エアコン購入費等助成について - 世田谷区', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は世田谷区公式サイトをもとにした概要です。対象条件・助成額・申請期間・受付状況は年度や個別事情により異なる場合があります。給付を保証するものではなく、最終的な可否は区の審査によります。必ず公式ページおよび担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
