insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-setagaya-air-conditioner-energy","status":"published","title":"低所得世帯エアコン購入費等助成（世田谷区）","officialUrl":"https://www.city.setagaya.lg.jp/02412/31918.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-setagaya-air-conditioner-energy:dG9reW8tc2V0YWdheWEtYWlyLWNvbmRpdGlvbmVy' from public.support_programs sp where sp.slug='tokyo-setagaya-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shibuya'), 'tokyo-shibuya-air-conditioner-energy', '渋谷区 エアコン購入費助成事業', '経済的な事情などにより自宅に使用できるエアコンがない、または故障している高齢者・低所得・生活保護世帯などを対象に、渋谷区がエアコン本体の購入代金と設置費用の一部（上限10万円）を助成する制度です。熱中症予防を目的としています。対象要件や上限額、受付期間は公式ページで確認してください。', '渋谷区では、住民税非課税世帯・児童扶養手当受給世帯・65歳以上のみの世帯（合計所得135万円以下）・生活保護世帯などのうち、自宅に使えるエアコンがない、または壊れている世帯に対し、エアコンの購入・設置費用を上限10万円まで助成しています。まず電話で相談し、訪問調査を受けてから申請する流れです。対象になるかどうかや金額は公式ページと所管課でご確認ください。', 'subsidy', '渋谷区内に住所があり、自宅に冷房機能を使えるエアコンが未設置または故障中の世帯のうち、(1)世帯全員が住民税（均等割・所得割）非課税、(2)児童扶養手当受給世帯、(3)65歳以上のひとり暮らしまたは65歳以上のみの世帯で合計所得135万円以下、(4)生活保護受給世帯（冷暖房器具支給要件に非該当）のいずれかに該当する方が対象となる可能性があります。詳細な要件は公式ページで確認してください。', '助成上限額10万円（エアコン本体の購入代金および設置に係る費用が対象。上限を超える分は自己負担）。金額は公式ページで確認してください。', '申請期間は「令和8年2月1日から令和8年10月31日まで」とされています（公式ページ記載／確認日2026-06-27時点では受付期間内）。受付期間は年度により変わる可能性があるため、最新の情報は公式ページで確認してください。', 'まず所管課（福祉部生活支援課生活支援係）に電話で連絡し、訪問調査を受けます。調査時に交付される申込書類一式をもとに見積書を取得し、エアコンを購入・設置したうえで販売店等を通じて申請する流れです。手続きの詳細は公式ページで確認してください。', '訪問調査時に交付される申込書類一式、見積書、申請書兼委任状など。詳細は公式ページおよび所管課で確認してください。', FALSE, '渋谷区 福祉部 生活支援課 生活支援係', '03-3463-2028', NULL, 'https://www.city.shibuya.tokyo.jp/kenko/iryo-kenko/teate-josei/eakon_josei.html', 'エアコン購入費助成事業 | 手当・助成 | 渋谷区ポータル', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'targetPeople', 'requiredDocumentsText']::text[], '本情報は渋谷区公式ページ（確認日2026-06-27）に基づく概要です。対象要件・助成額・受付期間は変更される場合があるため、申請前に必ず公式ページと所管課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
