insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-shibuya-air-conditioner-energy","status":"published","title":"渋谷区 エアコン購入費助成事業","officialUrl":"https://www.city.shibuya.tokyo.jp/kenko/iryo-kenko/teate-josei/eakon_josei.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-shibuya-air-conditioner-energy:dG9reW8tc2hpYnV5YS1haXItY29uZGl0aW9uZXIt' from public.support_programs sp where sp.slug='tokyo-shibuya-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nakano'), 'tokyo-nakano-air-conditioner-energy', '中野区 日常生活用具の給付（エアコンディショナー）', '中野区が、重度の障害がある方や難病患者等の日常生活を容易にするために行う『日常生活用具の給付』制度です。給付種目の一つとしてエアコンディショナーが定められており、種目ごとに設けられた限度額まで区が費用を負担します。対象となる手帳の等級・疾病などの要件や限度額、自己負担の有無は公式ページに数値が明記されておらず、障害者支援係への確認が必要です。', '中野区では、重い障害のある方や難病の方の暮らしを助けるための『日常生活用具の給付』があり、その対象品目のひとつにエアコンがあります。決められた上限額までは区が費用を負担します。対象になる障害の程度や上限額などは、区役所3階の障害者支援係(電話03-3228-8706)に確認してください。', 'subsidy', '中野区在住で、重度の障害がある方や難病患者等(対象となる障害者手帳の等級・疾病などの具体的要件は公式・窓口で確認)。高齢者・低所得世帯一般を広く対象とする制度ではありません。', 'エアコンディショナーを含む給付種目ごとに限度額が定められ、限度額までは区が負担します。具体的な限度額(基準額)はページに明記されていないため、公式・窓口でご確認ください。', '通年で相談・申請を受け付ける標準的な障害福祉の給付制度です(単年度の期間限定事業ではありません)。詳細は窓口でご確認ください。', '中野区役所3階の障害者等の相談窓口(障害者支援係)に申請・相談します。給付には事前の調査・申請が必要です。詳細は障害者支援係(電話03-3228-8706)へお問い合わせください。', '障害者手帳など対象要件を確認できる書類等が必要となる場合があります。必要書類は公式・窓口でご確認ください。', FALSE, '中野区 障害者支援係（障害者等の相談窓口・区役所3階）', '03-3228-8706', NULL, 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/syogai/taisyohinmokukakujyu/seikatsushien/yogu-jyutaku-kyufu.html', '日常生活用具、住宅改善の給付 | 中野区', '2026-06-27', 'high', ARRAY['targetPeople', 'benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '対象者の要件・限度額・自己負担の有無はページ本文に数値が明記されていないため、必ず中野区の障害者支援係で最新の内容をご確認ください。高齢者・低所得世帯向けの一般的なエアコン購入助成は別制度であり、本制度は障害福祉の用具給付です。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
