insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'suginami'), 'tokyo-suginami-air-conditioner-energy', 'エアコン購入費の助成（熱中症予防）', '杉並区が、経済的な理由で自宅用エアコンの購入が困難な低所得世帯を対象に、夏季の熱中症による健康被害の予防を目的として、エアコン本体の購入・設置費用の一部を助成する区独自の制度です。住民税非課税・均等割のみ課税世帯や児童扶養手当受給世帯などで、自宅にエアコンが無い、または既設エアコンが全て故障・15年以上経過している世帯が対象となる可能性があります。助成上限は区内販売店での購入で10万円、区外・インターネット販売での購入で8万円、1世帯につき1台までです。対象や金額・申請期間・受付状況は公式で必ずご確認ください。', '夏の暑さで体調を崩さないよう、収入が少なくてエアコンを買うのが難しい世帯に、杉並区がエアコンの購入・設置費用の一部を助成する制度です。住民税非課税世帯などが対象になる可能性があります。', 'subsidy', '杉並区に住民登録があり、令和7年度または8年度の住民税非課税世帯・均等割のみ課税世帯、もしくは令和7年度児童扶養手当受給世帯のいずれかに該当する世帯で、かつ自宅にエアコンが1台も無い、または既設エアコンが全て故障・15年以上経過している世帯が対象となる可能性があります（生活保護受給世帯を除く）。具体的な対象要件は公式で確認してください。', 'エアコン本体の購入・設置費用の一部を助成。区内販売店での購入は上限10万円、区外販売店・インターネット販売事業者からの購入は上限8万円。1世帯（住居）につき1台まで（1回限り）。金額は公式で確認してください。', '交付申請：令和8年6月1日〜9月30日（消印有効）。請求申請：令和8年6月1日〜令和9年1月31日（消印有効、予算到達時は終了）。', '電子申請または郵送による申請。交付申請の受付は令和8年6月1日から9月30日まで（消印有効）。対象エアコンは令和8年5月1日から令和9年1月31日までに購入したもの。請求申請は令和8年6月1日から令和9年1月31日まで（予算到達時は終了）。申請方法・期間は公式で必ず確認してください。', '申請書、本人確認資料の写し、住宅間取り図、申請時点の全部屋の写真など。該当者は児童扶養手当証書・課税証明書・エアコン製造年がわかる写真等が必要となる場合があります。詳細は公式で確認してください。', TRUE, 'すぎなみエアコン助成コールセンター', '050-1751-8542', NULL, 'https://www.city.suginami.tokyo.jp/s042/news/25347.html', 'エアコン購入費の助成を始めました｜杉並区公式ホームページ', '2026-06-27', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', '受付状況（単年度事業のため変動の可能性）']::text[], '本情報は杉並区公式ページに基づく概要です。対象・金額・申請期間・受付状況は変わることがあるため、申請前に必ず公式ページやコールセンターでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
