insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-suginami-air-conditioner-energy","status":"published","title":"エアコン購入費の助成（熱中症予防）","officialUrl":"https://www.city.suginami.tokyo.jp/s042/news/25347.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-suginami-air-conditioner-energy:dG9reW8tc3VnaW5hbWktYWlyLWNvbmRpdGlvbmVy' from public.support_programs sp where sp.slug='tokyo-suginami-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'toshima'), 'tokyo-toshima-air-conditioner-energy', '豊島区 エアコン購入費等助成（熱中症対策）', '豊島区が熱中症対策として実施する区独自のエアコン購入費等助成。低所得世帯（住民税非課税・均等割のみ世帯、児童扶養手当受給世帯など）や生活保護世帯を対象に、エアコンの購入・設置費用の一部を1世帯あたり1台限り上限10万円まで助成する可能性がある制度。令和8年6月1日より対象を拡大し年齢要件を撤廃。対象・上限額・申請窓口は世帯区分（65歳未満の低所得世帯／65歳以上を含む低所得世帯／生活保護世帯）によって異なるため、必ず豊島区公式で確認のこと。購入前に承認通知を受ける必要がある。', '暑さによる熱中症を防ぐため、豊島区が低所得の世帯や生活保護世帯にエアコンを買って取り付ける費用の一部（1台・上限10万円）を助成する制度です。買う前に区の承認を受ける必要があります。対象になるかどうかや申し込み先は世帯の状況によって変わるので、豊島区の公式ページや窓口で確認してください。', 'subsidy', '豊島区に住所があり、住民税非課税世帯・住民税均等割のみ世帯・児童扶養手当受給世帯などの低所得世帯、または生活保護世帯が対象となる可能性。過去にエアコン設置助成を受けていないこと等の要件があり、対象範囲・年齢要件は世帯区分により異なる。詳細・該当可否は必ず豊島区公式で確認してください。', '1世帯あたり1台限り、助成上限額10万円（公式で確認。世帯区分により取扱いが異なる場合があります）', '令和8年度の受付期間。低所得世帯（65歳未満）は令和8年6月1日～令和9年3月31日、高齢者世帯は令和8年4月1日～令和9年3月31日（請求期限あり）。年度ごとに変わるため公式で確認してください。', '電子申請（インターネット／LoGoフォーム）、郵送、または窓口で申請。購入前に承認通知を受けてから購入する必要があります。対象世帯区分により申請窓口が異なります（低所得・65歳未満＝くらし・居住支援課、低所得・65歳以上を含む＝高齢者福祉課、生活保護世帯＝生活福祉課）。最新の手続きは豊島区公式でご確認ください。', '申請書のほか、世帯状況や所得を確認する書類等が必要となる場合があります。詳細は豊島区公式または各申請窓口でご確認ください。', TRUE, '豊島区 くらし・居住支援課／高齢者福祉課／生活福祉課（世帯区分により異なる）', '03-4566-2420（エアコン助成事業コールセンター）', 'https://www.city.toshima.lg.jp/2506021621.html', 'https://www.city.toshima.lg.jp/2506021621.html', 'エアコンの購入費用等を一部助成します（豊島区公式ホームページ）', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', '対象経費にリサイクル料が含まれるか', '世帯区分ごとの細かな対象要件・上限額']::text[], '本ページは公開情報をもとにした概要です。対象要件・上限額・受付期間・申請窓口は変更される場合があり、世帯区分により異なります。最新かつ正確な情報と該当可否は、必ず豊島区の公式ホームページまたは担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
