insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-toshima-air-conditioner-energy","status":"published","title":"豊島区 エアコン購入費等助成（熱中症対策）","officialUrl":"https://www.city.toshima.lg.jp/2506021621.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-toshima-air-conditioner-energy:dG9reW8tdG9zaGltYS1haXItY29uZGl0aW9uZXIt' from public.support_programs sp where sp.slug='tokyo-toshima-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'kita'), 'tokyo-kita-air-conditioner-energy', '北区 住民税非課税高齢者世帯等エアコン購入費助成事業', '北区が、世帯全員が住民税非課税で高齢者・障害者・児童扶養手当受給世帯等を含む世帯、または既存の生活保護制度ではエアコンを設置できない生活保護受給世帯に対し、熱中症予防のためエアコン本体の購入費・設置費の一部を助成する区独自制度です。公式によると本体購入費は上限78,000円、設置費等を含め一世帯あたり最大100,000円・一台限りが目安とされています（金額・対象は公式で必ず確認）。なお北区では別枠で、東京ゼロエミポイントを利用して省エネエアコンを購入した高齢者・障害者向けに区が上乗せ助成する『高齢者及び障害者省エネエアコン購入費助成事業』も実施されていますが、対象・上限額・受付期間・申請窓口が異なるため、利用にあたっては必ず北区公式ページで各制度の最新情報を確認してください。', '夏の暑さによる熱中症を防ぐため、北区が高齢者や障害のある方、住民税が非課税の世帯などに、エアコンの購入や取り付けにかかる費用の一部を助成する区の制度です。お金が直接もらえるのではなく、決められた手続き（まず電話で申し込み、調査を受けてから対象店で購入）に沿って進める必要があります。対象になるかどうか、いくら助成されるか、いつまで申し込めるかは、必ず北区の公式ホームページや案内先の電話で確認してください。申請すれば必ず助成されるわけではなく、審査や予算の上限があります。', 'subsidy', '公式によると、世帯全員が住民税非課税で、65歳以上の高齢者・障害者・児童扶養手当受給世帯等を含む世帯、または既存の生活保護制度ではエアコンを設置できない生活保護受給世帯などが対象となる可能性があります。別枠の省エネエアコン助成は、東京ゼロエミポイントを利用して対象エアコンを購入した北区在住の高齢者・障害者が対象となる可能性があります。対象要件は年度や制度により異なるため、対象になるかどうかは必ず北区公式で確認してください。', '公式によると、住民税非課税世帯等向けの助成は本体購入費の上限78,000円、設置費等を含め一世帯あたり最大100,000円・一台限りが目安とされています。別枠の省エネエアコン助成は東京ゼロエミポイントへの区の上乗せ分です。助成額・上限・助成率は制度や年度により異なるため、金額は公式で必ず確認してください。', '住民税非課税世帯等向けの助成は令和8年5月7日から令和8年9月30日まで（2026年6月時点で受付中）とされ、予算上限到達時点で受付終了となる場合があり、令和8年度限りの時限事業で令和9年度以降の実施予定は現時点でないと案内されています。別枠の省エネエアコン助成（東京ゼロエミポイント上乗せ）は申請期限が令和8年3月31日とされています。受付期間・締切は変更される場合があるため、必ず公式で確認してください。', '住民税非課税世帯等向けの助成は、まずコールセンター（電話）へ申し込み、訪問調査を受け、購入前に交付決定を受けたうえで協力販売店で購入する流れとされています（購入後の申請は受け付けられない場合があります）。制度により申請方法が異なる場合があるため、申請前に北区公式ページおよび案内先で最新の手続きを確認してください。', '住民税非課税世帯等向けの助成では、訪問調査時に配布・案内される申請書一式、交付決定通知書、請求書類等が必要とされています。別枠の省エネエアコン助成では、エアコン購入時の領収書（レシート）の原本や東京ゼロエミポイントの交付決定通知書の原本が必要とされています。必要書類は制度・年度により異なるため、公式で確認してください。', FALSE, '北区 福祉部 生活福祉課 生活支援係（住民税非課税世帯等向け）／申込コールセンター', '03-3908-9004', 'https://www.city.kita.lg.jp/socialcare-health/welfare/1018289/1025282/1025283.html', 'https://www.city.kita.lg.jp/socialcare-health/welfare/1018289/1025282/1025283.html', '住民税非課税世帯等で一定の要件に該当する方にエアコン購入費を助成をします｜東京都北区', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'targetPeople', 'requiredDocumentsText', 'onlineApplicationAvailable', 'applicationMethodText', 'categorySlugs']::text[], '本情報は北区公式ページに基づく概要です。対象要件・助成上限額・受付期間・申請方法・必要書類は制度（住民税非課税世帯等向け／省エネエアコン上乗せ）ごと、また年度により異なります。住民税非課税世帯等向けの助成は令和8年度限りの時限事業とされ、令和9年度以降の実施予定は現時点でないと案内されています。最新かつ正確な内容は必ず北区公式ページおよび案内先電話で確認してください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
