insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-kita-air-conditioner-energy","status":"published","title":"北区 住民税非課税高齢者世帯等エアコン購入費助成事業","officialUrl":"https://www.city.kita.lg.jp/socialcare-health/welfare/1018289/1025282/1025283.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-kita-air-conditioner-energy:dG9reW8ta2l0YS1haXItY29uZGl0aW9uZXItZW5l' from public.support_programs sp where sp.slug='tokyo-kita-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'arakawa'), 'tokyo-arakawa-air-conditioner-energy', '低所得世帯向けエアコン購入費助成（荒川区）', '荒川区が、熱中症による健康被害の防止を目的に、低所得世帯に対してエアコンの購入・設置等にかかる費用を助成する区独自の制度です。世帯員全員が住民税所得割非課税である世帯、または児童扶養手当の受給世帯など一定の条件に該当し、使用できるエアコンを所有していない世帯が対象となる可能性があります。購入前に区役所の相談窓口で事前相談・書類交付を受け、指定店舗で購入する流れです。対象条件・助成上限額・申請期間は年度により異なり受付状況も変わるため、必ず荒川区公式ページで最新情報をご確認ください。', '荒川区では、夏の熱中症から命を守るため、収入が少ない世帯がエアコンを買うときの費用を区が助成してくれる制度があります。お金の少ない世帯で、使えるエアコンを持っていない場合が対象になることがあります。買う前に区役所の窓口で相談することが必要です。対象になるかどうかや金額は年度によって変わるので、必ず荒川区の公式ページで確かめてください。', 'subsidy', '世帯員全員が住民税所得割非課税（令和7年度）の世帯、または児童扶養手当の受給世帯などで、使用できるエアコンを所有していない（または故障により使用できるエアコンが居所に1台もない）低所得世帯が対象となる可能性があります。基準日（令和8年1月1日）時点で国内に住民登録があり、申請時点で荒川区に住民登録・区内に居所があることなどの要件があります。対象年度や基準は変わりうるため、詳しい対象条件は荒川区公式でご確認ください。', '1住所地あたり最大10万円（税込）程度とされ、本体購入費に上限（例：7万8千円）が設けられ、配送・設置工事・撤去・リサイクル費用などが対象経費に含まれる場合があります。上限額は年度により異なる可能性があるため公式でご確認ください。', '確認日（2026-06-27）時点では受付中（令和8年12月28日まで、設置完了は令和9年2月末まで）とされていますが、受付期間・締切は年度により変わるため、必ず荒川区公式ページで最新の受付状況をご確認ください。', '購入前に荒川区役所の相談窓口（福祉推進課 エアコン助成相談窓口）で事前相談を行い、エアコン購入に必要な書類の交付を受けたうえで指定店舗でエアコンを購入する流れとされています。購入後の申請では対象外となる場合があるため、必ず事前に公式手続きをご確認ください。', '来庁者の本人確認書類、代理人が来庁する場合は世帯主・代理人の本人確認書類および委任状、他自治体で住民登録があった場合は課税（非課税）証明書などが必要となる場合があります。詳細は公式でご確認ください。', FALSE, '荒川区 福祉推進課 地域共生推進係 エアコン助成相談窓口（がん予防・健康づくりセンター4階）', '03-3802-3111（内線3904）', NULL, 'https://www.city.arakawa.tokyo.jp/a026/fukushisuishin/airconjyosei/eakonnjyoseikinkaisi.html', '低所得世帯向けエアコン購入費助成 受付開始のお知らせ／荒川区公式サイト', '2026-06-27', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは荒川区公式サイトの情報をもとにした概要です。対象条件・助成額・申請期間・受付状況は変更される場合があります。申請の可否や受給は審査により決まり、必ず受給できるとは限りません。最新かつ正確な情報は必ず荒川区公式ページおよび相談窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
