insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-arakawa-air-conditioner-energy","status":"published","title":"低所得世帯向けエアコン購入費助成（荒川区）","officialUrl":"https://www.city.arakawa.tokyo.jp/a026/fukushisuishin/airconjyosei/eakonnjyoseikinkaisi.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-arakawa-air-conditioner-energy:dG9reW8tYXJha2F3YS1haXItY29uZGl0aW9uZXIt' from public.support_programs sp where sp.slug='tokyo-arakawa-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'itabashi'), 'tokyo-itabashi-air-conditioner-energy', '板橋区 エアコン購入費等助成（熱中症予防）', '板橋区が熱中症など健康被害の予防のために実施する、エアコン本体の購入・設置費用などを助成する区独自制度です。自宅にエアコンが1台も設置されていない（または故障して使えない）世帯のうち、低所得世帯・住民税非課税相当の高齢世帯・生活保護世帯等が対象となる可能性があります。対象費用にはエアコン本体の購入費、配送費、設置・工事費、古いエアコンの撤去費（リサイクル料を含む）が含まれるとされ、助成上限額は1世帯あたり10万円程度とされています。購入前に申請して交付決定を受ける必要があるなど条件があるため、最新の対象・金額・申請受付状況は必ず公式で確認してください。', '板橋区には、夏の暑さによる熱中症などを防ぐために、エアコンを買って取り付ける費用を助けてくれる制度があります。自宅にエアコンが1台もない（または壊れて使えない）世帯で、収入が少ない世帯や住民税がかからない高齢者の世帯などが対象になることがあります。助けてもらえる金額は1世帯あたり10万円くらいまでとされています。買う前に申し込んで「OK」の通知をもらう必要があるので、まずは区のコールセンター（0120-666-470）に電話で相談してください。年度によって対象や受付の時期が変わるので、最新の内容は区の公式ページで確かめてください。', 'subsidy', '板橋区民で、自宅にエアコンが1台も設置されていない（またはすべて故障して使えない）世帯のうち、低所得世帯・住民税非課税相当の高齢世帯・生活保護世帯等が対象となる可能性があります。年度や事業区分（高齢世帯向け／生活保護世帯等向け）によって対象要件が異なるため、ご自身が対象となるかは公式・コールセンターでご確認ください。', '助成上限額は1世帯あたり10万円程度とされています（エアコン購入費と上限額のいずれか少ない額）。金額は年度・事業区分により異なる可能性があるため公式でご確認ください。', '申請受付は年度ごとに期間が定められます。現行の生活保護世帯等向け事業は令和8年4月1日〜令和8年10月31日が申請受付期間とされ、請求期限は令和8年12月28日とされています（確認日時点）。なお高齢世帯向け事業など別区分は受付期間が異なり、すでに終了している場合があります。受付状況・期間は年度・事業区分により変わるため公式でご確認ください。', 'まず板橋区エアコン購入費助成金コールセンター（フリーダイヤル 0120-666-470、平日午前9時〜午後5時、土日祝・年末年始を除く）へ事前相談のうえ申請します。エアコンの購入前に申請し交付決定通知を受ける必要があり、交付決定前に購入した場合は対象外となるとされています。詳しい手続き・必要書類は公式でご確認ください。', '申請書のほか、対象要件の確認書類等が必要となる場合があります。詳細は公式・コールセンターでご確認ください。', FALSE, '板橋区エアコン購入費助成金コールセンター', '0120-666-470', NULL, 'https://www.city.itabashi.tokyo.jp/kusei/jorei/1015604/1015618/1015696.html', '福祉事務所 要綱集（板橋区生活保護世帯等エアコン購入費等助成事業実施要綱を掲載）｜板橋区公式ホームページ', '2026-06-27', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は板橋区公式ホームページをもとにした概要です。対象要件・助成額・申請受付期間・受付状況は年度や事業区分（高齢世帯向け／生活保護世帯等向け）により異なります。申請の可否や受給は審査によります。必ず公式情報・コールセンターで最新の内容をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
