insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nerima'), 'tokyo-nerima-air-conditioner-energy', 'エアコン購入費用助成（熱中症予防）', '練馬区が熱中症による健康被害の予防のため、自宅に使用できるエアコンが1台もない（または故障で動かない）住民税非課税・児童扶養手当受給・生活保護受給のいずれかに該当する世帯を対象に、エアコン本体および設置工事の費用を助成する区独自の制度です。助成上限は116,000円（本体78,000円まで＋設置工事38,000円まで・公式で確認）。詳細・最新の受付状況は必ず練馬区公式でご確認ください。', '暑さで体調を崩さないように、練馬区が「使えるエアコンが家にない・壊れて動かない」世帯のうち、住民税が非課税・児童扶養手当を受けている・生活保護を受けている、のいずれかにあてはまる世帯に、エアコン本体と取り付け工事の費用を助成する制度です。助成の上限は116,000円（本体78,000円まで、工事38,000円まで）とされています。申し込みは電話か区のオンラインフォームから。対象や受付期間は変わることがあるので、申し込む前に必ず練馬区の公式ページで確認してください。', 'subsidy', '自宅に冷房機能を使用できるエアコンが1台もない、または故障等で1台も動かない世帯で、かつ(1)世帯員全員が住民税非課税、(2)児童扶養手当を受給中、(3)生活保護を受給中、のいずれかに該当する世帯が対象となる可能性があります。過去に同助成を受けた世帯は対象外とされています。詳しい要件は練馬区公式でご確認ください。', '助成上限116,000円（エアコン本体78,000円まで＋設置工事38,000円まで）。対象は練馬区内に所在地のある店舗・事業者から購入し自宅に取り付ける新品のエアコンとされています（公式で確認）。金額・条件は年度により変わる可能性があります。', '令和8年度は申請が令和8年12月31日（木）まで、助成金請求が令和9年2月28日必着とされています（公式で確認・確認日2026-06-27時点）。受付期間や年度の取扱いは変わる可能性があるため、最新情報は公式でご確認ください。', '練馬区生活福祉課エアコン購入費助成担当（電話03-5984-1067）への申し込み、または公式ページのオンライン申込フォームから申請できるとされています。申請の前に必ず公式ページで要件・手順をご確認ください。', '必要書類は申請区分等により異なる可能性があるため、練馬区公式ページおよび担当窓口でご確認ください。', TRUE, '練馬区 福祉部 生活福祉課 エアコン購入費助成担当', '03-5984-1067', 'https://www.city.nerima.tokyo.jp/kurashi/jinken/komatta/airconjosei.html', 'https://www.city.nerima.tokyo.jp/kurashi/jinken/komatta/airconjosei.html', 'エアコン購入費用を助成します：練馬区公式ホームページ', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は練馬区公式ページ（確認日2026-06-27）にもとづく概要です。対象要件・助成額・受付期間・必要書類は変更される場合があります。申請の可否や助成額を保証するものではありません。必ず練馬区公式ページおよび担当窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
