insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-nerima-air-conditioner-energy","status":"published","title":"エアコン購入費用助成（熱中症予防）","officialUrl":"https://www.city.nerima.tokyo.jp/kurashi/jinken/komatta/airconjosei.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-nerima-air-conditioner-energy:dG9reW8tbmVyaW1hLWFpci1jb25kaXRpb25lci1l' from public.support_programs sp where sp.slug='tokyo-nerima-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'adachi'), 'tokyo-adachi-air-conditioner-energy', '気候変動適応対策エアコン購入費補助金（足立区）', '足立区が熱中症予防・気候変動適応の観点から実施する、対象世帯へのエアコン購入・設置費用の補助制度です。区内店舗で東京ゼロエミポイントを利用してエアコンを購入した、住民税非課税世帯・均等割のみ課税世帯・児童扶養手当受給世帯（ひとり親家庭等）などが対象となる可能性があり、補助上限は10万円とされています。対象範囲・上限額・受付状況は年度により変わるため、必ず足立区公式ページで確認してください。', '足立区にお住まいで、住民税非課税などの対象世帯の方が、区内のお店で対象のエアコンを買って設置した後に、購入・設置の費用の一部（上限10万円）を区から補助してもらえる可能性がある制度です。買う前に対象条件や受付状況を区の公式ページで確かめてください。', 'subsidy', '足立区内に住民登録があり、住民税非課税世帯・住民税均等割のみ課税世帯・児童扶養手当受給世帯（ひとり親家庭等）のいずれかに該当し、区内店舗で東京ゼロエミポイントを利用してエアコンを購入した方が対象となる可能性があります。生活保護受給世帯は対象外とされています。対象要件の詳細（高齢者のみ世帯・障害者世帯やエアコン未設置などの条件を含む）は公式ページで確認してください。', '補助上限10万円（対象経費が税込10万円に満たない場合は1,000円未満切捨て）とされています。金額は年度により変わる可能性があるため公式で確認してください。', '令和8年4月13日から令和9年2月26日まで（予算到達次第終了）とされています。受付期間・受付状況は変更される場合があるため、申請前に公式ページで最新の状況を確認してください。', 'エアコン購入後に郵送またはオンライン申請システムで申請する「設置後申請」方式とされています。提出先は環境部環境政策課管理係。申請手続きの詳細・必要書類は公式ページで確認してください。', '提出書類チェックリスト、補助金申請書、請求書兼口座振替依頼書、東京ゼロエミポイント利用やエアコン購入を証する書類等が必要とされています。詳細は公式ページの提出書類一覧で確認してください。', TRUE, '足立区 環境部環境政策課管理係', '03-3880-5935', 'https://www.city.adachi.tokyo.jp/kankyo/kikouhendoutekioutaisakueakon.html', 'https://www.city.adachi.tokyo.jp/kankyo/kikouhendoutekioutaisakueakon.html', '気候変動適応対策エアコン購入費補助金（設置後申請）｜足立区', '2026-06-27', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'categorySlugs']::text[], '本情報は足立区公式ページをもとに作成しています。対象者・上限額・申請期間・受付状況は年度や予算により変わるため、申請前に必ず公式ページおよび担当課で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
