insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-adachi-air-conditioner-energy","status":"published","title":"気候変動適応対策エアコン購入費補助金（足立区）","officialUrl":"https://www.city.adachi.tokyo.jp/kankyo/kikouhendoutekioutaisakueakon.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-adachi-air-conditioner-energy:dG9reW8tYWRhY2hpLWFpci1jb25kaXRpb25lci1l' from public.support_programs sp where sp.slug='tokyo-adachi-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'katsushika'), 'tokyo-katsushika-air-conditioner-energy', '葛飾区 非課税世帯等エアコン購入費等助成事業', '葛飾区が、自宅に冷房機能のあるエアコンが1台もない非課税世帯等に対し、熱中症予防のためエアコン本体の購入費・設置工事費の一部を助成する区独自制度です。対象や上限額・受付期間は年度ごとに更新されるため、必ず葛飾区公式で最新情報をご確認ください。', '葛飾区にお住まいで、家に効くエアコンが1台もない非課税の世帯などが、エアコンを買って取り付ける費用の一部（本体と工事あわせて最大で約11万円）を区から助成してもらえる制度です。買う前に区へ申請して、対象に決まってから購入する必要があります。対象や金額・受付時期は年度で変わるので、公式ページで最新情報を確認してください。', 'subsidy', '葛飾区に住民登録があり居住し、自宅に冷房機能のあるエアコンが1台もない世帯のうち、(1)住民税が世帯全員非課税・免除・均等割のみ課税、または(2)生活保護受給中で生活保護制度の支給対象外の世帯などが対象となる可能性があります。過去に本助成を受けていないことなどの要件があるため、対象の詳細は公式でご確認ください。', '公式情報（令和8年度）では、エアコン本体購入費は78,000円（税込）、設置工事費は33,000円（税込）を上限とし、合計で最大111,000円（税込）とされています。上限額は年度により変わる可能性があるため、必ず公式でご確認ください。', '令和8年度は、対象確認調査の申請が令和8年4月13日〜10月31日（消印有効）、助成金の申請・請求が決定後〜12月31日（消印有効）とされています。受付期間は年度ごとに更新されるため公式でご確認ください。', '事前申請制です。購入前に区へ対象確認調査の申請を行い、助成金交付対象に決定されてから対象のエアコンを購入する必要があります。申請は郵送またはオンライン（電子申請フォーム）で行い、電話での申請はできません。受付期間（対象確認調査申請：令和8年4月13日〜10月31日消印有効など）や必要書類は年度により変わるため、公式で最新情報をご確認ください。', '申請書のほか、世帯全員の非課税証明書等（税情報が区で確認できない場合）が必要になる場合があります。詳細・最新の必要書類は公式でご確認ください。', TRUE, '葛飾区 福祉管理課 エアコン助成担当', '03-5654-6872', 'https://www.city.katsushika.lg.jp/kenkou/1000055/1035297/index.html', 'https://www.city.katsushika.lg.jp/kenkou/1000055/1035297/index.html', '令和8年度葛飾区非課税世帯等エアコン購入費等助成事業｜葛飾区公式サイト', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'targetPeople', 'requiredDocumentsText']::text[], '本情報は葛飾区公式サイトの確認時点の内容に基づく概要であり、対象・上限額・受付期間・必要書類は変更される場合があります。申請の可否や受給は区の審査により決まります。最終的な条件・手続きは必ず葛飾区公式・担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
