insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot air-conditioner-energy import', '{"slug":"tokyo-katsushika-air-conditioner-energy","status":"published","title":"葛飾区 非課税世帯等エアコン購入費等助成事業","officialUrl":"https://www.city.katsushika.lg.jp/kenkou/1000055/1035297/index.html","topic":"air-conditioner-energy"}'::jsonb, 'pilot:tokyo-katsushika-air-conditioner-energy:dG9reW8ta2F0c3VzaGlrYS1haXItY29uZGl0aW9u' from public.support_programs sp where sp.slug='tokyo-katsushika-air-conditioner-energy' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'edogawa'), 'tokyo-edogawa-air-conditioner-energy', '江戸川区 住民税非課税世帯等エアコン購入費助成金', '熱中症による健康被害を防ぐため、エアコンがない、または故障で使用できない世帯のうち、住民税非課税世帯・住民税均等割のみ課税世帯・児童扶養手当受給世帯を対象に、エアコン本体の購入費および設置費を助成する江戸川区独自の制度です。1世帯1台限りで、助成上限額は公式で確認した範囲で最大10万円です。生活保護受給世帯等は各福祉事務所への相談が案内されています。対象要件や受付期間、助成上限額は年度により異なる場合があるため、必ず江戸川区の公式ページで最新情報をご確認ください。', '夏の暑さによる熱中症を防ぐため、エアコンがない、または壊れて使えない世帯で、住民税が非課税などの条件にあてはまる場合に、エアコンの購入・設置費用の一部を区が助成する制度です。1世帯につき1台までで、助成の上限は公式で確認した範囲では最大10万円です。申請はコールセンターへの郵送で行います。受付期間が決まっているので、利用を考える場合は江戸川区の公式ページで最新の条件や期間を確認してください。', 'subsidy', '江戸川区内に住み、エアコンがない、または故障で使用できない世帯のうち、住民税非課税世帯・住民税均等割のみ課税世帯・児童扶養手当受給世帯のいずれかに該当する世帯が対象となる可能性があります。生活保護受給世帯・中国残留邦人等支援給付受給世帯は別途、各福祉事務所への相談が案内されています。対象の詳細・所得要件は公式ページで確認してください。', 'エアコン本体の購入費および設置費について、1世帯1台限りで助成。公式ページで確認した範囲では助成上限額は最大100,000円ですが、年度や予算により異なる場合があるため公式で確認してください。', '公式ページでは令和8年度の受付期間を令和8年5月15日から令和8年8月31日まで(消印有効)と案内しています。受付期間は単年度で設定され年度ごとに変わるため、必ず最新の公式情報を確認してください。', '必要書類(交付申請書等)を「えどがわエアコン助成コールセンター」へ郵送して申請します。オンライン申請は不可で郵送のみです。受付期間が定められているため、申請を検討する場合は早めに公式ページで最新の受付状況・必要書類を確認してください。', '交付申請書(第1号様式)、申請前チェックシート、本人確認書類の写し、エアコンの販売予定価格がわかる資料などが案内されています。課税状況に応じて住民税課税証明書等が必要になる場合があります。詳細・最新の必要書類は公式ページで確認してください。', FALSE, 'えどがわエアコン助成コールセンター', '03-6706-7980', 'https://www.city.edogawa.tokyo.jp/e091/kenko/fukushikaigo/sekatsuhogo/konkyu_sodan/r8eakon.html', 'https://www.city.edogawa.tokyo.jp/e091/kenko/fukushikaigo/sekatsuhogo/konkyu_sodan/r8eakon.html', '令和8年度江戸川区住民税非課税世帯等エアコン購入費助成金 江戸川区ホームページ', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '対象要件・助成上限額・受付期間・必要書類は年度や予算により変わる場合があります。本ページは江戸川区公式情報をもとにした概要であり、実際の申請可否は審査によります。必ず江戸川区の公式ページおよびコールセンターで最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
