insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.chiyoda.lg.jp/koho/kenko/sekatsu/airconditioner-josei.html', '敵対的検証実施（2026-06-27）。officialUrl（https://www.city.chiyoda.lg.jp/koho/kenko/sekatsu/airconditioner-josei.html）をWebFetchで直接取得し全項目を照合。(a)到達=200で到達確認。(b)許可ホスト=www.city.chiyoda.lg.jp（.lg.jp）でFAQ専用ドメイン等の非公式は不使用、合格。(c)当該区ページ=千代田区独自の「低所得世帯・生活保護受給世帯に対するエアコンの購入費助成」そのもののページ、合格。(d)受付状況=令和8年度事業として申請相談受付が令和8年5月1日～10月16日、本日2026-06-27は受付期間内のため現在受付中＝found維持で妥当（注:一次調査のresearchNoteは生活保護受給世帯窓口を「生活支援課相談・保護係03-5211-4216」、低所得世帯コールセンターを03-5211-4231としており公式と一致）。(e)国/都制度の誤認なし=区独自の熱中症対策施策で正しい。(f)対象の一部を全体と記載していない=対象は住民税非課税/均' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chiyoda' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.chuo.lg.jp/a0019/kenkouiryou/fukushiippan/seikatsushien/airconjosei.html', '敵対検証完了。program.officialUrl をWebFetchで取得し到達確認（404でない）。(a)到達OK。(b)許可ホスト一致＝www.city.chuo.lg.jp（.lg.jp かつ city.*）。FAQ専用ドメインではない。(c)中央区自身の「住民税非課税世帯等エアコン購入費助成」当該区ページであることを確認。(d)掲載日2026-04-01（令和8年度事業）、受付終了・単年度終了の記載なし＝現在受付中と判断。区の「自然エネルギー・省エネルギー機器等導入費助成」（住宅用/事業所用）は別制度であり混同していないことをWebSearchでも確認（別URL・別所管a0036）。(e)東京ゼロエミポイント等の国/都制度を区独自と誤認していない。(f)対象3区分（住民税非課税/生活保護/中国残留邦人等支援給付）を全体として正しく記述。(g)複数制度の混在なし。(h)非断定表現（可能性があります・公式で確認）を維持。申請受付期間・締切は公式ページに明記がなくuncertainFieldsに計上済みで妥当。1点だけ是正：公式ページは「自宅にエアコンが1台もない、または故障で冷' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chuo' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
