insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.shinjuku.lg.jp/fukushi/fukushi01_000001_00037.html', '敵対的検証完了。program.officialUrl（https://www.city.shinjuku.lg.jp/fukushi/fukushi01_000001_00037.html）をWebFetchで2回取得し全項目を照合。(a)到達OK。(b)ホスト www.city.shinjuku.lg.jp は city.*.lg.jp で許可ホスト一致。(c)当該ページは新宿区独自の「新宿区低所得世帯・生活保護受給世帯に対するエアコン購入費助成」（事業名: 新宿区エアコン購入費助成事業）で、エアコン購入費助成そのものの区ページであることを確認。(d)受付中: 対象は令和7・8年度（2025/2026年度）の住民税非課税/均等割課税世帯等、申請受付終了（予定）令和8年9月30日、ページ最終更新2026-06-12 → 過年度のみ・終了済みではなく現在受付中。(e)東京ゼロエミポイント等の都/国制度の単なる案内ではなく区の独立事業であることを確認（別の都制度案内ページ korei01_000001_00149.html は不採用で正しい）。(f)対象は4区分（住民税非課税/均等割のみ' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinjuku' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
