insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.sumida.lg.jp/kenko_fukushi/seikatuhukusi/eakon.html', 'WebFetchで墨田区公式（www.city.sumida.lg.jp＝.lg.jp かつ city.* の許可ホスト）の「墨田区住民税非課税世帯等エアコン購入費助成事業について」ページ（更新日2026-03-21）を検証し、一次調査の内容が公式記載と一致することを確認した。(a)到達OK (b)許可ホスト一致（FAQ専用ドメインではない区公式直下ページ）(c)墨田区独自のエアコン購入費助成そのものの当該区ページ (d)受付期間=令和8年3月23日〜8月31日／申込期限=令和8年7月31日。調査時点2026-06-27は受付期間内かつ申込期限前＝現在受付中（過年度のみ・終了済みではない）(e)国/都の一般説明ではなく区独自事業 (f)対象（住民税非課税世帯〔令和7or8年度・世帯全員非課税〕＋生活保護世帯で、エアコンが1台もない/全台故障）を全体として記述 (g)単一制度のみ (h)上限額・対象・期間は概括＋「公式で確認」を付して非断定。助成上限=合計最大111,000円（購入費73,000円＋設置工事費38,000円、税込）、申込=すみだエアコン助成コールセンター03-6821-6' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='sumida' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
