insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-seikatsukomaru/20230428084925.html', '敵対的検証完了(2026-06-27)。一次調査のofficialUrlをWebFetchで2回取得し全項目を照合。(a)到達=200で取得成功。(b)許可ホスト=www.city.shinagawa.tokyo.jp(.tokyo.jp・品川区公式)で適合、FAQ専用ドメインではない。(c)当該区ページ=「品川区住民税非課税世帯エアコン購入費等助成事業」という品川区独自のエアコン購入費助成そのものの専用ページ。(d)受付状況=ページは令和8年4月15日更新、申請期間「令和8年5月1日(金)〜7月31日(金)」で、確認日(令和8年6月27日)は受付窓内=現在受付中、過年度/終了済みではない。(e)国/都制度との誤認なし=区独自事業として正しく記述。一次調査は別制度(環境課のゼロカーボン助成・東京都の高齢者/障害者向け)の存在も注記しつつ本件を低所得世帯向けエアコン助成1件に正しく限定。(f)対象の過大/過小化なし=住民税非課税世帯(令和7or8年度非課税)かつ自宅に使用可能エアコン0台、生活保護受給世帯は「臨時的一般生活費における冷房器具の支給要件に該当しない世帯」という公式文言を正確' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinagawa' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.meguro.tokyo.jp/fukushisougou/kenkoufukushi/seikatsushien/airconditioner.html', '敵対検証実施（2026-06-27）。WebFetchでprogram.officialUrl（city.meguro.tokyo.jp＝.tokyo.jp許可ホスト）に到達確認。(a)到達OK (b)許可ホスト一致・FAQ専用ドメインでない (c)目黒区公式の当該区エアコン購入費助成ページそのもの＝制度名「非課税等高齢者世帯のエアコン購入費助成」を確認 (d)令和8年度（2026年度）事業として現在受付中。予約・申請書提出期限=令和8年9月30日、助成金請求期限=令和8年11月30日でいずれも検証日（2026-06-27）より将来＝過年度/受付終了ではない。foundを維持 (e)国/都制度の一般説明ではなく区独自制度 (f)対象を概括し一部を全体と書いていない（高齢者のみ世帯または高齢者＋障害者のみ世帯で世帯全員が住民税非課税または生活保護受給中）(g)単一制度のみで混在なし (h)上限10万円・対象要件・各種期限は「公式で確認」「とされています」等の非断定表現で概括。WebSearch（city.meguro.tokyo.jpドメイン限定）でも同一ページ・上限10万円・対象要件・' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='meguro' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/shien/eaconjosei.html', '敵対的検証完了（2026-06-27）。(a)officialUrlはWebFetchで到達確認。(b)ホストはwww.city.ota.tokyo.jp＝city.*.tokyo.jpの許可official host（FAQ専用ドメインではない）。(c)当該ページは「大田区エアコン設置緊急支援事業」そのものの大田区独自制度ページであり、国・都制度の一般説明ではない。(d)受付期間は令和8年6月1日～令和9年2月28日と明記、確認日（令和8年=2026年6月27日）時点で受付中＝過年度のみ/終了ではない。(e)複数制度の混入なし（別途存在する65歳以上限定の気候変動適応対策補助金や東京ゼロエミポイントは本programに混ぜていない）。(f)対象の一部を全体と書いていない。(g)断定表現なし・上限額/期間/対象は概括＋「公式で確認」で適切に非断定。\n是正点1件：categorySlugsの『nursing-care』とlifeEventSlugsの『caregiving』は公式の対象要件（非課税世帯・均等割のみ課税世帯・児童扶養手当受給世帯）に裏付けがなく、生活困窮支援の性格に反する' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='ota' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.setagaya.lg.jp/02412/31918.html', '敵対的検証を実施。program.officialUrl（https://www.city.setagaya.lg.jp/02412/31918.html）をWebFetchで取得し、(a)到達=正常表示・404やエラーなし (b)許可ホスト=www.city.setagaya.lg.jp（.lg.jp/city.*に合致） (c)当該区=世田谷区独自の「低所得世帯エアコン購入費等助成」そのもののページ (d)受付状況=過年度終了ではなく令和8年(2026)4/15〜10/30の受付期間中・ページ更新日2026-05-29・代理受領払い開始の記載あり（現行・有効） (e)国/都制度の誤認なし=区独自制度として正しく記述 (f)対象の一部を全体と誤記なし=対象要件（自宅にエアコン1台もない／世帯全員が住民税非課税または均等割のみ課税／世田谷区民／生活保護非受給）が公式と一致 (g)複数制度の混在なし=別制度の生活保護世帯向け助成と区別済み (h)非断定=「公式で確認してください」を全体に付し断定を回避、をすべて確認。主要事実（上限10万円・1世帯1台1回限り・申請期間・オンライン(LOG' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='setagaya' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.shibuya.tokyo.jp/kenko/iryo-kenko/teate-josei/eakon_josei.html', '敵対的検証完了（確認日2026-06-27）。一次調査のofficialUrlをWebFetchで取得し、渋谷区公式ポータル（www.city.shibuya.tokyo.jp＝許可ホスト.tokyo.jp/city.*に一致、FAQ専用ドメインでない）の「エアコン購入費助成事業」当該区ページであることを確認。(a)到達OK (b)許可ホスト一致 (c)渋谷区独自のエアコン助成ページ (d)申請期間=令和8年2月1日〜令和8年10月31日（2026-02-01〜2026-10-31）で確認日時点は受付期間内・「受付終了/募集終了」表記なし→found維持 (e)国/都制度の誤認なし＝渋谷区独自事業 (f)対象を全体と誤記なし＝4要件＋「エアコン未設置 又は 故障中（冷房機能が作動しない）」を原文で再確認、一次調査の記載と一致 (g)複数制度の混在なし (h)上限額・対象・期間は概括＋公式確認の非断定で記述済。最終更新2026-04-16。上限10万円・電話03-3463-2028・オンライン申請なしも公式ページと一致。受付期間・対象・上限は年度変動の可能性ありuncertainFiel' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shibuya' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/syogai/taisyohinmokukakujyu/seikatsushien/yogu-jyutaku-kyufu.html', '敵対的検証(2026-06-27)。一次調査のcoverage=not_found_on_official_siteを是正してfoundとした。経緯: 一次調査は対象URLを中野区環境部「省エネルギー設備等の設置補助事業」(https://www.city.tokyo-nakano.lg.jp/kurashi/kankyo/ondankataisaku/0686241120240301112636655.html)に置いていたが、WebFetchで確認するとこのページの対象は太陽光発電・蓄電システム・高断熱窓/ドア・ハイブリッド給湯器・エネファーム・エコキュートのみで、エアコン本体は対象外(かつ後期受付終了)。一次調査の『エアコン区独自制度は確認できない』という結論はこの省エネ事業に依拠していた。しかし障害福祉のWebSearchから別の公式ページ「日常生活用具、住宅改善の給付」(https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/syogai/taisyohinmokukakujyu/seikatsushien/yogu-jyutaku' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='nakano' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.suginami.tokyo.jp/s042/news/25347.html', '敵対的検証完了。program.officialUrl（https://www.city.suginami.tokyo.jp/s042/news/25347.html）をWebFetchで取得し、全項目を一次ページと照合した。(a)到達=正常にアクセス可、ページID25347・2026年6月22日更新。(b)許可ホスト=www.city.suginami.tokyo.jp（city.*／.tokyo.jp、杉並区公式ドメイン。FAQ専用ドメインではない）に合致。(c)当該区ページ=杉並区のエアコン購入費助成そのものの専用ページであることを確認。(d)受付状況=交付申請 令和8年6月1日〜9月30日、請求申請 令和8年6月1日〜令和9年1月31日。本日2026-06-27は受付期間内のため現在受付中（過年度のみ／終了済みではない。ページ本文も現在進行中の制度・受付終了していないと明記）。(e)国/都制度の誤認なし=区独自制度。(f)対象の一部を全体と誤記なし=targetPeopleは「該当する世帯」「可能性があります」と概括＋公式確認を付記。(g)複数制度の混在なし=単一制度。(h)断' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='suginami' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
