insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.itabashi.tokyo.jp/kusei/jorei/1015604/1015618/1015696.html', '板橋区のエアコン購入費助成について敵対検証を実施し、coverage=found・ok=true と判定した。officialUrl は到達可能で公式許可ホスト（.tokyo.jp）。当該『板橋区生活保護世帯等エアコン購入費等助成事業実施要綱』（令和8年3月23日区長決定）を掲載する福祉事務所要綱集ページであり、確認日（2026-06-27）時点で令和8年度版の申請受付期間内。区独自制度で国・都の一般制度との混同なし。非断定で公式確認を促す記述も適切。詳細・留意点は issues 参照。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='itabashi' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.nerima.tokyo.jp/kurashi/jinken/komatta/airconjosei.html', '敵対的検証完了（確認日2026-06-27）。program.officialUrl（https://www.city.nerima.tokyo.jp/kurashi/jinken/komatta/airconjosei.html）をWebFetchで取得し、一次調査の全項目を独立に再確認した。(a)到達OK。(b)ホスト city.nerima.tokyo.jp は許可ホスト（.tokyo.jp／city.*）に合致しFAQ専用ドメインではない。(c)練馬区独自の「エアコン購入費用を助成します」当該区ページであることを確認。(d)受付期間＝申込令和8年12月31日まで／助成金請求令和9年2月28日必着で、確認日時点で受付中。過年度のみ・終了済みではないため found 維持（needs_review不要）。(e)国/都制度（東京ゼロエミ等）ではなく練馬区独自制度であることをページ本文の目的・主体記述から確認、誤認なし。(f)対象は「自宅に動作するエアコンが1台もない」かつ(1)世帯全員住民税非課税(2)児童扶養手当受給(3)生活保護受給のいずれか、という要件を正しく全体として記載して' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='nerima' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.adachi.tokyo.jp/kankyo/kikouhendoutekioutaisakueakon.html', '敵対的検証: program.officialUrl（https://www.city.adachi.tokyo.jp/kankyo/kikouhendoutekioutaisakueakon.html）をWebFetchで直接取得し全チェック項目を点検。(a)到達=ページ正常表示（404/エラーなし）。(b)許可ホスト=city.adachi.tokyo.jp（.tokyo.jpのワードドメイン、FAQ専用ドメインではない）で合致。(c)足立区独自のエアコン購入費補助そのものの当該区ページであることを本文で確認。(d)受付状況=本文に「【受付中】」と明記、申請期間=令和8年4月13日〜令和9年2月26日（予算到達次第終了）でFY2026の現行制度。過年度のみ/受付終了ではない。(e)東京ゼロエミポイント利用が前提条件だが補助制度自体は足立区独自であり、国/都制度の誤認なし。(f)対象は所得要件世帯（住民税非課税/均等割のみ課税/児童扶養手当受給世帯）を全体として正しく記述し一部を全体と誤記していない。(g)複数制度の混在なし。(h)断定回避・区差のある対象/上限/期間は概括＋「公式で' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='adachi' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.katsushika.lg.jp/kenkou/1000055/1035297/index.html', '敵対的検証完了（2026-06-27）。program.officialUrl（https://www.city.katsushika.lg.jp/kenkou/1000055/1035297/index.html）をWebFetchで2回取得し、以下を確認。(a)到達OK。(b)許可ホスト：www.city.katsushika.lg.jp は .lg.jp / city.* に該当しFAQ専用ドメインでない＝OK。(c)当該区ページ：「令和8年度葛飾区非課税世帯等エアコン購入費等助成事業」で葛飾区独自のエアコン購入費助成そのもの＝OK。(d)受付状況：令和8年度（現年度）で受付期間は対象確認調査申請が令和8年4月13日〜10月31日（将来期間）、助成金申請は決定後〜12月31日。「受付終了」等の文言なし＝現在受付中（過年度のみ/終了ではない）。(e)国/都の一般制度の誤認なし＝区独自制度と明記。(f)対象を一部→全体と断定せず「可能性があります」「公式で確認」で概括＝OK。(g)複数制度の混在なし＝単一制度。(h)FORBIDDEN/断定なし、上限額・対象・期間・必要書類は概括＋「' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='katsushika' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.edogawa.tokyo.jp/e091/kenko/fukushikaigo/sekatsuhogo/konkyu_sodan/r8eakon.html', '敵対的検証を実施し、一次調査を支持(ok=true)。(a)到達: 公式ページをWebFetchで取得成功。(b)許可ホスト: www.city.edogawa.tokyo.jp は city.*.tokyo.jp 形式の公式ホストで許可対象。(c)当該区ページ: 「令和8年度江戸川区住民税非課税世帯等エアコン購入費助成金」は江戸川区独自のエアコン助成専用ページであり、公式の生活保護・生活困窮ページ(/e091/.../sekatsuhogo/index.html)の新着情報からリンクされていることを独立に確認。(d)現在受付中: ページは令和8年度(FY2026)、更新日2026-05-26、受付期間=令和8年5月15日〜令和8年8月31日(消印有効)。検証日2026-06-27時点で受付中。過年度でも受付終了でもない。終了表記があるのは別制度の75歳以上向け熱中症・物価高騰対策(5,000円)であり、一次調査が正しく区別・除外している。(e)国/都制度の誤認なし: 区独自制度。(f)対象の一部を全体と誤記なし: 3区分(住民税非課税世帯/均等割のみ課税世帯/児童扶養手当受給世帯)を' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='edogawa' and t.slug='air-conditioner-energy' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
